import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Link } from 'react-scroll';
import { HiMenuAlt3, HiX } from 'react-icons/hi';

const NAV_LINKS = [
  { label: 'About', to: 'about' },
  { label: 'Projects', to: 'projects' },
  { label: 'Skills', to: 'skills' },
  { label: 'Experience', to: 'experience' },
  { label: 'Education', to: 'education' },
  { label: 'Contact', to: 'contact' },
];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <motion.header
      initial={{ y: -80, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ duration: 0.7, ease: 'easeOut' }}
      className={`fixed top-0 inset-x-0 z-50 transition-all duration-300 ${
        scrolled
          ? 'bg-[#0a0a0f]/80 backdrop-blur-2xl border-b border-white/[0.06] shadow-xl shadow-black/20'
          : ''
      }`}
    >
      <nav className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
        {/* Logo */}
        <Link to="hero" smooth duration={500} className="cursor-pointer select-none">
          <span className="font-mono text-lg font-bold tracking-tight">
            <span className="text-[#6c63ff]">//</span>
            <span className="bg-gradient-to-r from-[#6c63ff] to-[#38bdf8] bg-clip-text text-transparent">
              hana.ai
            </span>
          </span>
        </Link>

        {/* Desktop links */}
        <ul className="hidden md:flex items-center gap-1">
          {NAV_LINKS.map(({ label, to }) => (
            <li key={to}>
              <Link
                to={to}
                smooth
                duration={500}
                offset={-64}
                className="relative px-4 py-2 text-sm text-slate-400 hover:text-white font-medium cursor-pointer transition-colors duration-200 rounded-lg hover:bg-white/[0.04] group block"
              >
                {label}
                <span className="absolute bottom-1 left-1/2 -translate-x-1/2 w-0 h-px bg-gradient-to-r from-[#6c63ff] to-[#38bdf8] group-hover:w-4 transition-all duration-300" />
              </Link>
            </li>
          ))}
        </ul>

        {/* Hire Me CTA */}
        <a
          href="mailto:hanaharis95@gmail.com"
          className="hidden md:flex items-center gap-2 px-4 py-1.5 rounded-lg text-sm font-semibold text-[#6c63ff] border border-[#6c63ff]/40 bg-[#6c63ff]/10 hover:bg-[#6c63ff]/20 hover:border-[#6c63ff]/60 transition-all duration-200"
        >
          Hire Me
        </a>

        {/* Mobile burger */}
        <button
          onClick={() => setOpen(!open)}
          className="md:hidden p-2 text-slate-400 hover:text-white transition-colors"
        >
          {open ? <HiX size={22} /> : <HiMenuAlt3 size={22} />}
        </button>
      </nav>

      {/* Mobile menu */}
      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="md:hidden overflow-hidden bg-[#0d0d18]/95 backdrop-blur-2xl border-b border-white/[0.06]"
          >
            <ul className="px-6 py-4 flex flex-col gap-1">
              {NAV_LINKS.map(({ label, to }) => (
                <li key={to}>
                  <Link
                    to={to}
                    smooth
                    duration={500}
                    offset={-64}
                    onClick={() => setOpen(false)}
                    className="block py-3 px-4 text-slate-400 hover:text-white text-sm font-medium cursor-pointer rounded-lg hover:bg-white/[0.04] transition-colors"
                  >
                    {label}
                  </Link>
                </li>
              ))}
              <li className="pt-2">
                <a
                  href="mailto:hanaharis95@gmail.com"
                  className="block text-center py-2.5 rounded-lg text-sm font-semibold text-[#6c63ff] border border-[#6c63ff]/40 bg-[#6c63ff]/10"
                >
                  Hire Me
                </a>
              </li>
            </ul>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.header>
  );
}
